import { visit } from 'unist-util-visit';

// Astro does NOT rewrite href/src attributes written in markdown prose or in
// custom component templates — it only prefixes `base` onto assets it
// resolves itself (images through astro:assets, sidebar/pagination links
// generated by Starlight's own components). Any root-relative link a docs
// author writes by hand (e.g. `[Quick Start](/docs/quickstart)`) is left
// untouched, which breaks entirely once `base` is non-root (as it is for
// this GitHub Pages project site, `/hyve-website`).
//
// This plugin walks the rendered HTML of every markdown/MDX page and
// prepends `base` to any href/src that starts with a single `/` (skipping
// protocol-relative `//` and anything already prefixed). It only sees raw
// markdown-authored elements — hrefs generated *inside* Astro components
// (e.g. our Card.astro) are rendered after this runs and are fixed
// separately, at the component level.
export function rehypeBaseLinks(base) {
  const cleanBase = base.replace(/\/$/, '');
  if (!cleanBase) return () => {};

  return () => (tree) => {
    visit(tree, 'element', (node) => {
      for (const attr of ['href', 'src']) {
        const value = node.properties?.[attr];
        if (
          typeof value === 'string' &&
          value.startsWith('/') &&
          !value.startsWith('//') &&
          !value.startsWith(cleanBase + '/') &&
          value !== cleanBase
        ) {
          node.properties[attr] = cleanBase + value;
        }
      }
    });
  };
}
